import os
import zipfile
import tarfile
import rarfile
import 7z

def extract_archive(thepath, format):
    if format == "zip":
        return _extract_zip(thepath)
    elif format == "tar":
        return _extract_tar(thepath)
    elif format == "rar":
        return _extract_rar(thepath)
    elif format == "7z":
        return _extract_7z(thepath)
    else:
        raise ValueError("Invalid format: {}".format(format))

def _extract_zip(thepath):
    zip_ref = zipfile.ZipFile(thepath, 'r')
    zip_ref.extractall(os.path.dirname(thepath))
    zip_ref.close()

def _extract_tar(thepath):
    with tarfile.open(thepath, 'r') as tar:
        tar.extractall()

def _extract_rar(thepath):
    rar_filename = os.path.basename(thepath)
    rar_file = rarfile.RarFile(thepath)
    counter = 0
    for file in rar_file.infolist():
        rar_filename = rar_filename + '-' + file.date_time.year + '-' + file.date_time.month + '-' + file.date_time.day
        counter += 1
        rar_file.extract(file, '.')  # Extracting all to current directory
        rar_file.close()

def _extract_7z(thepath):
    with 7z.open(thepath) as archive:
        archive.extractall()
